import SwiftUI
import Shared

struct ContentView: View {
    private let greeting = Greeting().greet()

    var body: some View {
        VStack(spacing: 24) {
            Text("Radiacode")
                .font(.largeTitle)
                .fontWeight(.semibold)
            Text(greeting)
                .font(.body)

            if #available(iOS 26.0, *) {
                Button("Liquid Glass") { }
                    .buttonStyle(.glassProminent)
            } else {
                Button("Tap me") { }
                    .buttonStyle(.borderedProminent)
            }
        }
        .padding()
    }
}

#Preview {
    ContentView()
}

